      CREATE view [SSRS].[JuniorLeague_SeasonCurrLast_EndofSeason]     as    Select * FROM   (  SELECT League_ID        ,REPLACE(REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' '),'+',' plus') AS Name        ,[year_of_Fixture]        ,sum(isnull([No Result] ,0))    [No Result]        ,sum(isnull([Abandoned] ,0))    [Abandoned]        ,sum(isnull([Cancelled] ,0))    [Cancelled]        ,sum(isnull([Conceded] ,0))    [Conceded]        ,sum(isnull([InProgress] ,0))    [InProgress]        ,sum(isnull([Win]   ,0))   [Win]    FROM [SSRS].[JuniorLeagues_SeasonTD_2022]    Group by [League_ID]        ,[Name]        ,[year_of_Fixture]    UNION    Select    --League_ID   League_ID        ,REPLACE(REPLACE(REPLACE(REPLACE(Name,'&','and'),'/',' '),':',' '),'+',' plus') AS Name        ,[year_of_Fixture]        ,sum(isnull([No Result] ,0))    [No Result]        ,sum(isnull([Abandoned] ,0))    [Abandoned]        ,sum(isnull([Cancelled] ,0))    [Cancelled]        ,sum(isnull([Conceded] ,0))    [Conceded]        ,sum(isnull([InProgress] ,0))    [InProgress]        ,sum(isnull([Win]   ,0))   [Win]  FROM    [SSRS].JuniorLeagues_2021Season     Group by [League_ID]        ,[Name]        ,[year_of_Fixture]     )A        --Where League_ID = 15363                